package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;

import java.security.MessageDigest;
import java.util.Base64;

public class DefaultDataProcessor implements DataProcessor {

    @Override
    public DataMessage process(DataMessage input) throws Exception {
        String type = input.getType();

        switch (type.toUpperCase()) {
            case "ECHO":
                return input.toBuilder()
                    .setType("ECHO_RESPONSE")
                    .putHeaders("processed", "true")
                    .build();

            case "CHECKSUM":
                MessageDigest digest = MessageDigest.getInstance("SHA-256");
                byte[] hash = digest.digest(input.getPayload().toByteArray());
                String checksum = Base64.getEncoder().encodeToString(hash);
                return DataMessage.newBuilder()
                    .setId(input.getId())
                    .setType("CHECKSUM_RESPONSE")
                    .setPayload(ByteString.copyFromUtf8(checksum))
                    .putHeaders("algorithm", "SHA-256")
                    .build();

            case "TRANSFORM":
                byte[] transformed = transformPayload(input.getPayload().toByteArray());
                return DataMessage.newBuilder()
                    .setId(input.getId())
                    .setType("TRANSFORM_RESPONSE")
                    .setPayload(ByteString.copyFrom(transformed))
                    .putHeaders("original_size", String.valueOf(input.getPayload().size()))
                    .putHeaders("transformed_size", String.valueOf(transformed.length))
                    .build();

            default:
                return DataMessage.newBuilder()
                    .setId(input.getId())
                    .setType("UNKNOWN_TYPE_RESPONSE")
                    .putHeaders("original_type", type)
                    .putHeaders("status", "unhandled")
                    .build();
        }
    }

    private byte[] transformPayload(byte[] data) {
        // Example transformation - in production this could be compression,
        // encryption, format conversion, etc.
        byte[] result = new byte[data.length];
        for (int i = 0; i < data.length; i++) {
            result[i] = (byte) (data[i] ^ 0xFF);
        }
        return result;
    }
}

