package com.dataprocessing.grpc;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.netty.shaded.io.grpc.netty.NettyServerBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class GrpcServer {

    private static final Logger logger = LoggerFactory.getLogger(GrpcServer.class);

    private final int port;
    private final Server server;
    private final FileServiceImpl fileService;

    public GrpcServer(int port) {
        this(port, new FileServiceImpl());
    }

    public GrpcServer(int port, FileServiceImpl fileService) {
        this.port = port;
        this.fileService = fileService;

        this.server = NettyServerBuilder.forPort(port)
            // Accept arbitrary message sizes from clients
            .maxInboundMessageSize(Integer.MAX_VALUE)
            .maxInboundMetadataSize(16 * 1024 * 1024) // 16MB metadata
            // Connection settings
            .keepAliveTime(60, TimeUnit.SECONDS)
            .keepAliveTimeout(20, TimeUnit.SECONDS)
            .permitKeepAliveWithoutCalls(true)
            .permitKeepAliveTime(10, TimeUnit.SECONDS)
            // Flow control for large streaming transfers
            .flowControlWindow(4 * 1024 * 1024) // 4MB flow control window
            .maxConcurrentCallsPerConnection(100)
            // Thread pool for handling requests
            .executor(Executors.newFixedThreadPool(
                Runtime.getRuntime().availableProcessors() * 2))
            // Register service and interceptors
            .addService(fileService)
            .addService(new HealthServiceImpl())
            .intercept(new LoggingInterceptor())
            .build();
    }

    public void start() throws IOException {
        server.start();
        logger.info("gRPC Server started on port {}", port);
        logger.info("Max inbound message size: unlimited (Integer.MAX_VALUE)");

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server...");
            try {
                GrpcServer.this.stop();
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
            logger.info("gRPC server shut down.");
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            fileService.shutdown();
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
            if (!server.isTerminated()) {
                server.shutdownNow();
            }
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        int port = 9090;
        if (args.length > 0) {
            port = Integer.parseInt(args[0]);
        }

        GrpcServer server = new GrpcServer(port);
        server.start();
        server.blockUntilShutdown();
    }
}

