package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class FileServiceClient implements AutoCloseable {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceClient.class);
    private static final int CHUNK_SIZE = 64 * 1024; // 64KB

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceStub asyncStub;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;

    public FileServiceClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
            .maxInboundMessageSize(Integer.MAX_VALUE)
            .usePlaintext()
            .keepAliveTime(60, TimeUnit.SECONDS)
            .keepAliveTimeout(20, TimeUnit.SECONDS)
            .build();

        this.asyncStub = FileServiceGrpc.newStub(channel);
        this.blockingStub = FileServiceGrpc.newBlockingStub(channel);
    }

    public UploadStatus uploadFile(Path filePath) throws InterruptedException, IOException {
        final CountDownLatch finishLatch = new CountDownLatch(1);
        final UploadStatus[] result = new UploadStatus[1];
        final Throwable[] error = new Throwable[1];

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                result[0] = status;
                logger.info("Upload result: success={}, message={}, bytes={}",
                    status.getSuccess(), status.getMessage(), status.getBytesReceived());
            }

            @Override
            public void onError(Throwable t) {
                error[0] = t;
                logger.error("Upload failed", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                finishLatch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        String filename = filePath.getFileName().toString();
        long fileSize = Files.size(filePath);

        try (InputStream inputStream = new BufferedInputStream(
                new FileInputStream(filePath.toFile()), 256 * 1024)) {

            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                    .setFilename(filename)
                    .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                    .setOffset(offset)
                    .setTotalSize(fileSize)
                    .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                // Check for errors from server
                if (finishLatch.getCount() == 0) {
                    break;
                }
            }
        }

        requestObserver.onCompleted();
        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Upload timed out");
        }

        if (error[0] != null) {
            throw new RuntimeException("Upload failed", error[0]);
        }

        return result[0];
    }

    public void downloadFile(String filename, Path outputPath) throws InterruptedException, IOException {
        final CountDownLatch finishLatch = new CountDownLatch(1);
        final Throwable[] error = new Throwable[1];

        FileRequest request = FileRequest.newBuilder()
            .setFilename(filename)
            .build();

        try (OutputStream outputStream = new BufferedOutputStream(
                new FileOutputStream(outputPath.toFile()), 256 * 1024)) {

            StreamObserver<FileChunk> responseObserver = new StreamObserver<FileChunk>() {
                @Override
                public void onNext(FileChunk chunk) {
                    try {
                        outputStream.write(chunk.getContent().toByteArray());
                    } catch (IOException e) {
                        error[0] = e;
                    }
                }

                @Override
                public void onError(Throwable t) {
                    error[0] = t;
                    logger.error("Download failed", t);
                    finishLatch.countDown();
                }

                @Override
                public void onCompleted() {
                    logger.info("Download completed: {}", filename);
                    finishLatch.countDown();
                }
            };

            asyncStub.downloadFile(request, responseObserver);

            if (!finishLatch.await(5, TimeUnit.MINUTES)) {
                throw new RuntimeException("Download timed out");
            }
        }

        if (error[0] != null) {
            throw new RuntimeException("Download failed", error[0]);
        }
    }

    public void processDataBidirectional(java.util.List<DataMessage> messages)
            throws InterruptedException {

        final CountDownLatch finishLatch = new CountDownLatch(1);

        StreamObserver<DataMessage> responseObserver = new StreamObserver<DataMessage>() {
            @Override
            public void onNext(DataMessage response) {
                logger.info("Received processed data: id={}, type={}, size={}",
                    response.getId(), response.getType(), response.getPayload().size());
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Bidirectional stream error", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed");
                finishLatch.countDown();
            }
        };

        StreamObserver<DataMessage> requestObserver = asyncStub.processData(responseObserver);

        for (DataMessage message : messages) {
            requestObserver.onNext(message);
            // Small delay to avoid overwhelming the server
            Thread.sleep(10);
        }

        requestObserver.onCompleted();

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Bidirectional processing timed out");
        }
    }

    @Override
    public void close() {
        try {
            channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
            if (!channel.isTerminated()) {
                channel.shutdownNow();
            }
        } catch (InterruptedException e) {
            channel.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }

    public static void main(String[] args) throws Exception {
        String host = "localhost";
        int port = 9090;

        try (FileServiceClient client = new FileServiceClient(host, port)) {
            // Example: Upload a file
            if (args.length > 0) {
                Path uploadPath = Path.of(args[0]);
                logger.info("Uploading file: {}", uploadPath);
                UploadStatus status = client.uploadFile(uploadPath);
                logger.info("Upload status: {}", status);

                // Example: Download the file back
                Path downloadPath = Path.of("/tmp/downloaded_" + uploadPath.getFileName());
                logger.info("Downloading file to: {}", downloadPath);
                client.downloadFile(uploadPath.getFileName().toString(), downloadPath);
            }

            // Example: Bidirectional data processing
            java.util.List<DataMessage> messages = java.util.List.of(
                DataMessage.newBuilder()
                    .setId("msg-1")
                    .setType("ECHO")
                    .setPayload(ByteString.copyFromUtf8("Hello, gRPC!"))
                    .build(),
                DataMessage.newBuilder()
                    .setId("msg-2")
                    .setType("CHECKSUM")
                    .setPayload(ByteString.copyFromUtf8("Compute my checksum"))
                    .build(),
                DataMessage.newBuilder()
                    .setId("msg-3")
                    .setType("TRANSFORM")
                    .setPayload(ByteString.copyFrom(new byte[]{1, 2, 3, 4, 5}))
                    .build()
            );

            logger.info("Starting bidirectional data processing...");
            client.processDataBidirectional(messages);
        }
    }
}